import sympy as sp
q,z=sp.symbols('q z')
def qint(k): return sum(q**i for i in range(k))
def compute_F(N):
    # Stir q: dict
    Stir={(0,0): sp.Integer(1)}
    F={}
    for n in range(1,N+1):
        for k in range(1,n+1):
            val=Stir.get((n-1,k-1),0)+qint(k)*Stir.get((n-1,k),0)
            Stir[(n,k)]=sp.expand(val)
            F[(n,k)]=sp.expand(sp.prod(qint(j) for j in range(1,k+1))*val)
    return Stir,F
Stir,F=compute_F(6)
def H(n):
    return sp.expand(sum(z**(n-k)*F[(n,k)] for k in range(1,n+1)))
for n in [4,5]:
    G=sp.expand((H(n)-1)/(q+z))
    print("n",n, "G", sp.Poly(G,z))
    for b in range(n):
        gb=sp.expand(sp.Poly(G,z).coeff_monomial(z**b))
        print("b",b, gb)
